#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int X, A, B, C;
        scanf("%d %d %d %d", &X, &A, &B, &C);
        int p[3] = {A, B, C};
        // simple sorting network for 3 elements
        if (p[0] > p[1]) { int t = p[0]; p[0] = p[1]; p[1] = t; }
        if (p[1] > p[2]) { int t = p[1]; p[1] = p[2]; p[2] = t; }
        if (p[0] > p[1]) { int t = p[0]; p[0] = p[1]; p[1] = t; }
        long long ans = (long long)(X - 1) * p[0] + p[1];
        printf("%lld\n", ans);
    }
    return 0;
}

