    while(T--) {
        long long X; int A,B,C; cin>>X>>A>>B>>C;
        int p[3] = {A,B,C};
        sort(p, p+3);
        long long ans = (X-1)*p[0] + p[1];
        cout<<ans<<"\n";
    }
    return 0;
